DROP TABLE IF EXISTS `quran_verb_canonical`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `quran_verb_canonical` (
  `root_ar` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Racine en arabe, espaces entre lettres (ex: "ك ت ب")',
  `verb_form` tinyint(3) unsigned NOT NULL DEFAULT '1' COMMENT 'Forme I à X (1-10). 1 par défaut pour les entrées Form I.',
  `voice` enum('active','passive') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `past_3ms` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'الماضي — 3e masc. sing. (ex: كَتَبَ)',
  `present_3ms` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'المضارع — 3e masc. sing. (ex: يَكْتُبُ)',
  `imperative_2ms` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'الأمر — 2e masc. sing. (ex: اُكْتُبْ)',
  `masdar` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'المصدر (ex: كِتَابَة)',
  `active_participle` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'اسم الفاعل (ex: كَاتِب)',
  `passive_participle` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'اسم المفعول (ex: مَكْتُوب)',
  `source` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Qutrub | dictionary | manual',
  PRIMARY KEY (`root_ar`,`verb_form`,`voice`),
  KEY `idx_root` (`root_ar`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

